import { supabase } from '../lib/supabase'

function toUser(row) {
  return {
    id:                    row.id,
    name:                  row.name,
    email:                 row.email,
    credits:               row.credits ?? 0,
    freeDownloadUsed:      row.free_download_used ?? false,
    firstUpgradePurchased: row.first_upgrade_purchased ?? false,
    plan:                  row.plan ?? 'free',
  }
}

async function getProfile(userId) {
  const { data, error } = await supabase
    .from('users')
    .select('*')
    .eq('id', userId)
    .single()
  if (error) throw new Error(error.message)
  return toUser(data)
}

export const authApi = {
  register: async (name, email, password) => {
    const { data, error } = await supabase.auth.signUp({
      email: email.trim().toLowerCase(),
      password,
      options: { data: { name: name.trim() } },
    })
    if (error) throw new Error(error.message)
    if (!data.user) throw new Error('Erro ao criar conta')

    const userId = data.user.id

    const { data: existing } = await supabase
      .from('users')
      .select('id')
      .eq('id', userId)
      .maybeSingle()

    if (!existing) {
      await supabase.from('users').insert({
        id:                      userId,
        name:                    name.trim(),
        email:                   email.trim().toLowerCase(),
        credits:                 0,
        free_download_used:      false,
        first_upgrade_purchased: false,
        plan:                    'free',
      })
    }

    const profile = await getProfile(userId)
    return { token: data.session?.access_token ?? '', user: profile }
  },

  login: async (identifier, password) => {
    let email = identifier.trim()

    if (!email.includes('@')) {
      const { data, error } = await supabase
        .from('users')
        .select('email')
        .ilike('name', email)
        .limit(1)
      if (error || !data?.length) throw new Error('Usuário ou senha incorretos')
      email = data[0].email
    } else {
      email = email.toLowerCase()
    }

    const { data, error } = await supabase.auth.signInWithPassword({ email, password })
    if (error) throw new Error('Usuário ou senha incorretos')

    const profile = await getProfile(data.user.id)
    return { token: data.session.access_token, user: profile }
  },

  me: async () => {
    const { data: { user } } = await supabase.auth.getUser()
    if (!user) throw new Error('Sessão expirada. Faça login novamente.')
    return getProfile(user.id)
  },

  forgotPassword: async (email) => {
    const { error } = await supabase.auth.resetPasswordForEmail(
      email.trim().toLowerCase(),
      { redirectTo: window.location.origin }
    )
    if (error) throw new Error(error.message)
    return { ok: true }
  },

  resetPassword: async (_token, password) => {
    const { error } = await supabase.auth.updateUser({ password })
    if (error) throw new Error(error.message)
    return { ok: true }
  },

  updateCredits: async (_token, credits, freeDownloadUsed, firstUpgradePurchased) => {
    const { data: { user } } = await supabase.auth.getUser()
    if (!user) return
    await supabase.from('users').update({
      credits,
      free_download_used:      freeDownloadUsed,
      first_upgrade_purchased: firstUpgradePurchased,
    }).eq('id', user.id)
  },
}

import { supabase } from '../lib/supabase'

async function currentUserId() {
  const { data: { user } } = await supabase.auth.getUser()
  if (!user) throw new Error('Não autenticado')
  return user.id
}

export const projectsApi = {
  list: async (_token) => {
    const userId = await currentUserId()
    const { data, error } = await supabase
      .from('projects')
      .select('id, name, updated_at')
      .eq('user_id', userId)
      .order('updated_at', { ascending: false })
    if (error) throw new Error(error.message)
    return data
  },

  save: async (_token, id, name, data) => {
    const userId = await currentUserId()
    const now = new Date().toISOString()
    if (id) {
      const { error } = await supabase
        .from('projects')
        .update({ name, data, updated_at: now })
        .eq('id', id)
        .eq('user_id', userId)
      if (error) throw new Error(error.message)
      return { id, name }
    } else {
      const newId = crypto.randomUUID()
      const { error } = await supabase.from('projects').insert({
        id:         newId,
        user_id:    userId,
        name,
        data,
        created_at: now,
        updated_at: now,
      })
      if (error) throw new Error(error.message)
      return { id: newId, name }
    }
  },

  load: async (_token, id) => {
    const userId = await currentUserId()
    const { data, error } = await supabase
      .from('projects')
      .select('*')
      .eq('id', id)
      .eq('user_id', userId)
      .single()
    if (error) throw new Error('Projeto não encontrado')
    return data
  },

  delete: async (_token, id) => {
    const userId = await currentUserId()
    const { error } = await supabase
      .from('projects')
      .delete()
      .eq('id', id)
      .eq('user_id', userId)
    if (error) throw new Error(error.message)
    return { ok: true }
  },
}

