// Returns 'free' | 'ok' | 'upgrade_required'. Server is the source of truth —
// it actually debits credits, so a client can't bypass the 40-credit gate.
tryExport: async () => {
  const s = get()
  if (!s.token) {
    // Not logged in: no server-side credits to enforce, so we still gate
    // client-side to avoid silently granting unlimited free exports.
    if (!s.freeDownloadUsed) {
      lsSet(FREE_USED_KEY, 'true')
      set({ freeDownloadUsed: true })
      return 'free'
    }
    set({ showUpgradeModal: true })
    return 'upgrade_required'
  }
  try {
    const res = await fetch('/api/auth/consume-export', {
      method: 'POST',
      headers: { Authorization: `Bearer ${s.token}` },
    })
    if (res.status === 402) {
      set({ showUpgradeModal: true })
      return 'upgrade_required'
    }
    if (!res.ok) throw new Error('export gate failed')
    const data = await res.json()
    lsSet(CREDITS_KEY, String(data.credits))
    lsSet(FREE_USED_KEY, 'true')
    set({ credits: data.credits, freeDownloadUsed: true })
    return data.freeDownload ? 'free' : 'ok'
  } catch (e) {
    // Backend unreachable — fail closed on the credits gate but don't
    // block the very first free download from working offline-ish.
    if (!s.freeDownloadUsed) {
      set({ freeDownloadUsed: true })
      return 'free'
    }
    set({ showUpgradeModal: true })
    return 'upgrade_required'
  }
},

